mapper.select:
SELECT 
FROM domain_package_workflow_binding
WHERE package_id = #{packageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND stable_key = #{stableKey}

SELECT 
FROM domain_package_workflow_binding


        AND package_id = #{filter.packageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND version_id = #{filter.versionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


        AND trigger = #{filter.trigger}


        AND process_definition_key = #{filter.processDefinitionKey}


        AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}


ORDER BY id ASC
LIMIT #{size}

SELECT 
FROM domain_package_workflow_binding
WHERE package_id = #{packageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND (version_id IS NULL

           OR version_id = #{versionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

      )
ORDER BY created_at ASC

SELECT 
FROM domain_package_workflow_binding
WHERE process_definition_key = #{processDefinitionKey}
  AND business_version = #{businessVersion}

    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}
